domain_model:
{
  "domainKit": {
    "name": "School Management",
    "description": "Dominio para la gestión integral de colegios, incluyendo control de asistencia, administración de alumnos y facturación mensual.",
    "boundedContexts": [
      {
        "name": "Student Management",
        "description": "Contexto dedicado a la administración de la información de los alumnos y sus familias.",
        "coreEntities": [
          {
            "name": "Student",
            "attributes": ["studentId", "firstName", "lastName", "dateOfBirth", "nationalId", "enrollmentDate", "status (ACTIVE, INACTIVE, GRADUATED)"],
            "businessRules": ["El alumno debe tener un tutor legal principal asignado al momento de la inscripción.", "El estado del alumno determina su elegibilidad para tomar asistencia o ser facturado."]
          },
          {
            "name": "LegalGuardian",
            "attributes": ["guardianId", "firstName", "lastName", "relationship", "email", "primaryPhone", "secondaryPhone", "address"],
            "businessRules": ["Debe existir al menos un tutor legal por alumno.", "El tutor principal es el responsable de la facturación."]
          },
          {
            "name": "Enrollment",
            "attributes": ["enrollmentId", "student", "gradeLevel", "section", "academicYear", "enrolledDate"],
            "businessRules": ["Un alumno solo puede tener una matrícula activa por año académico.", "La matrícula debe estar activa para registrar asistencia."]
          }
        ],
        "relationships": ["Student (1) -> (*) LegalGuardian (a través de un objeto de valor 'Guardianship')", "Student (1) -> (*) Enrollment (histórico)", "Enrollment (1) -> (1) GradeLevel"]
      },
      {
        "name": "Attendance",
        "description": "Contexto para el registro y control diario de la asistencia de los alumnos.",
        "coreEntities": [
          {
            "name": "AttendanceRecord",
            "attributes": ["recordId", "date", "student", "status (PRESENT, ABSENT, LATE, EXCUSED)", "notes", "recordedBy", "recordedAt"],
            "businessRules": ["Solo se puede registrar asistencia para alumnos con matrícula activa en la fecha del registro.", "No se puede modificar un registro de asistencia después de 24 horas sin autorización especial."]
          },
          {
            "name": "AttendanceSummary",
            "attributes": ["summaryId", "student", "month", "year", "daysPresent", "daysAbsent", "daysLate"],
            "businessRules": ["El resumen se calcula automáticamente a partir de los registros diarios.", "Es la fuente de verdad para reportes y posibles descuentos por asistencia en la facturación."]
          }
        ],
        "relationships": ["Student (1) -> (*) AttendanceRecord", "Student (1) -> (*) AttendanceSummary (por mes/año)", "AttendanceSummary se deriva de múltiples AttendanceRecord."]
      },
      {
        "name": "Billing",
        "description": "Contexto encargado de la generación, emisión y seguimiento de las facturas mensuales.",
        "coreEntities": [
          {
            "name": "Invoice",
            "attributes": ["invoiceId", "invoiceNumber", "student", "billingMonth", "issueDate", "dueDate", "subtotal", "adjustments (descuentos/recargos)", "totalAmount", "status (DRAFT, ISSUED, PARTIALLY_PAID, PAID, OVERDUE, CANCELLED)", "paymentMethod"],
            "businessRules": ["La factura se genera mensualmente basada en la tarifa del grado y la asistencia del mes anterior.", "El 'totalAmount' se calcula como: subtotal + adjustments.", "Una factura en estado ISSUED no puede cambiar su subtotal o descuentos base."]
          },
          {
            "name": "FeeStructure",
            "attributes": ["feeId", "gradeLevel", "effectiveDate", "monthlyTuition", "enrollmentFee", "otherFees"],
            "businessRules": ["Solo puede haber una tarifa activa por 'gradeLevel' en un momento dado.", "Las facturas nuevas usan la tarifa activa al momento de su generación."]
          },
          {
            "name": "Payment",
            "attributes": ["paymentId", "invoice", "amount", "paymentDate", "receivedBy", "referenceNumber"],
            "businessRules": ["El pago no puede exceder el total pendiente de la factura.", "Un pago registrado cambia el estado de la factura correspondiente."]
          }
        ],
        "relationships": ["Student (1) -> (*) Invoice", "Invoice (1) -> (*) Payment", "GradeLevel (1) -> (*) FeeStructure (histórico)", "FeeStructure se aplica a muchas Invoice."]
      },
      {
        "name": "School Administration",
        "description": "Contexto para la gestión de la estructura del colegio, grados, aulas y personal.",
        "coreEntities": [
          {
            "name": "School",
            "attributes": ["schoolId", "name", "address", "phone", "email", "academicCalendar"],
            "businessRules": ["Es la raíz agregada principal para toda la configuración."]
          },
          {
            "name": "GradeLevel",
            "attributes": ["gradeId", "internalCode", "name", "description", "order"],
            "businessRules": ["El código interno debe ser único dentro del colegio."]
          },
          {
            "name": "Classroom",
            "attributes": ["classroomId", "identifier", "gradeLevel", "capacity", "primaryTeacher"],
            "businessRules": ["Un aula está asignada a un único grado/nivel, pero un grado puede tener múltiples aulas."]
          }
        ],
        "relationships": ["School (1) -> (*) GradeLevel", "School (1) -> (*) Classroom", "GradeLevel (1) -> (*) Classroom"]
      }
    ],
    "sharedKernel": {
      "valueObjects": [
        {
          "name": "Money",
          "attributes": ["amount", "currency"]
        },
        {
          "name": "PersonName",
          "attributes": ["firstName", "lastName"]
        },
        {
          "name": "DateRange",
          "attributes": ["startDate", "endDate"]
        },
        {
          "name": "Address",
          "attributes": ["street", "city", "state", "postalCode", "country"]
        }
      ],
      "enums": ["StudentStatus", "AttendanceStatus", "InvoiceStatus", "RelationshipType"]
    },
    "packageBase": "com.application"
  }
}
